#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""Find residual contention + confirm sustained enrich rate (exit-0-safe). Names what the
58 lock-waiters wait on, measures rate over 50s, and reports queue drain."""
import os,sys,json,time,subprocess
def psql(q,t=18):
    r=subprocess.run(["sudo","-u","postgres","psql","tuanichat_atlas","-tAc",q],capture_output=True,text=True,timeout=t)
    return (r.stdout.strip() if r.returncode==0 else "ERR")
out={"kind":"residual","ts":int(time.time())}
try:
    out["blocker_chain"]=psql("""SELECT blocking_pid||' blocks '||cnt||' | '||state||' '||round(age_s)||'s | '||substr(regexp_replace(q,'\\s+',' ','g'),1,75) FROM (
      SELECT bl.pid AS blocking_pid, count(*) cnt, max(a.state) state, max(extract(epoch from now()-a.query_start)) age_s, max(a.query) q
      FROM pg_stat_activity w JOIN LATERAL unnest(pg_blocking_pids(w.pid)) AS bl(pid) ON true
      JOIN pg_stat_activity a ON a.pid=bl.pid GROUP BY bl.pid ORDER BY cnt DESC LIMIT 6) s""")
    out["wait_events"]=psql("SELECT coalesce(wait_event_type,'none')||'/'||coalesce(wait_event,'none')||':'||count(*) FROM pg_stat_activity WHERE state='active' OR wait_event_type='Lock' GROUP BY 1 ORDER BY count(*) DESC LIMIT 8")
    # sustained rate over 50s
    d0=psql("SELECT count(*) FILTER (WHERE status='done') FROM atlas.enrich_queue").split('\n')[-1]; t0=time.time()
    time.sleep(50)
    d1=psql("SELECT count(*) FILTER (WHERE status='done') FROM atlas.enrich_queue").split('\n')[-1]; t1=time.time()
    out["done_t0"]=d0; out["done_t1"]=d1
    try: out["sustained_per_min"]=round((int(d1)-int(d0))*60.0/(t1-t0),1)
    except Exception: pass
    out["active"]=psql("SELECT count(*) FROM pg_stat_activity WHERE state='active'").split('\n')[-1]
    out["total"]=psql("SELECT count(*)||'/'||current_setting('max_connections') FROM pg_stat_activity").split('\n')[-1]
    out["pending"]=psql("SELECT count(*) FILTER (WHERE status='pending') FROM atlas.enrich_queue").split('\n')[-1]
except Exception as e:
    out["error"]=str(e)
def envf(p):
    d={}
    try:
        for ln in open(p):
            ln=ln.strip()
            if ln.startswith('export '): ln=ln[7:]
            if '=' in ln and not ln.startswith('#'):
                k,v=ln.split('=',1); d[k.strip()]=v.strip().strip('"').strip("'")
    except Exception: pass
    return d
try:
    import base64,urllib.request,urllib.error
    env=envf("/etc/atlas/autopull.env"); tok=env.get("STATUS_TOKEN") or os.environ.get("STATUS_TOKEN"); repo=env.get("STATUS_REPO") or "cloudwalker171/atlas-manifests"
    url="https://api.github.com/repos/%s/contents/status/hetzner/residual.json"%repo; sha=None
    if tok:
        try:
            r=urllib.request.Request(url+"?ref=main",headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas"}); sha=json.load(urllib.request.urlopen(r,timeout=20)).get("sha")
        except Exception: sha=None
        body={"message":"residual","content":base64.b64encode(json.dumps(out,indent=2,default=str).encode()).decode(),"branch":"main"}
        if sha: body["sha"]=sha
        for _ in range(6):
            try:
                rq=urllib.request.Request(url,data=json.dumps(body).encode(),method="PUT",headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas","Content-Type":"application/json"}); urllib.request.urlopen(rq,timeout=25); break
            except urllib.error.HTTPError as e:
                if e.code==409:
                    try:
                        rq2=urllib.request.Request(url+"?ref=main",headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas"}); body["sha"]=json.load(urllib.request.urlopen(rq2,timeout=20)).get("sha")
                    except Exception: pass
                else: break
            except Exception: time.sleep(2)
except Exception: pass
sys.exit(0)
